import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;

class Logger {
  static void log(String message) {
    debugPrint('[LOG] $message');
  }

  static void logHttpRequest(String url, Map<String, String> headers, String body) {
    debugPrint('[HTTP REQUEST] URL: $url, Headers: ${_redactHeaders(headers)}, Body: ${_redactSensitiveData(body)}');
  }

  static void logHttpResponse(String url, int statusCode, String responseBody) {
    debugPrint('[HTTP RESPONSE] URL: $url, Status Code: $statusCode, Response: ${_redactSensitiveData(responseBody)}');
  }

  static void logDatabaseOperation(String operation, String query) {
    debugPrint('[DB OPERATION] Operation: $operation, Query: $query');
  }

  static void logAuthenticationFlow(String step, String details) {
    debugPrint('[AUTH FLOW] Step: $step, Details: ${_redactSensitiveData(details)}');
  }

  static void logUserInteraction(String interaction, String details) {
    debugPrint('[USER INTERACTION] Interaction: $interaction, Details: $details');
  }

  static String _redactSensitiveData(String data) {
    // Redact sensitive information like tokens and passwords
    return data.replaceAll(RegExp(r'(token|password)=[^&\s]+'), '$1=REDACTED');
  }

  static Map<String, String> _redactHeaders(Map<String, String> headers) {
    // Redact sensitive headers
    return headers.map((key, value) => MapEntry(key, key.toLowerCase() == 'authorization' ? 'REDACTED' : value));
  }
}

